-- {"operators": "FILTER,WINDOW", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER"}
SELECT C_W_ID, C_D_ID, C_ID, C_LAST, C_BALANCE, NTILE(4) OVER (PARTITION BY C_W_ID ORDER BY C_BALANCE DESC) AS balance_quartile, NTILE(10) OVER (PARTITION BY C_W_ID, C_D_ID ORDER BY C_BALANCE DESC) AS balance_decile FROM CUSTOMER WHERE C_BALANCE IS NOT NULL;
